163	const CAP_MULTIPLIER = 2;
164	const HIGH_ENCHANTMENT_CLAIM_THRESHOLD = 8;
165	const HIGH_ENCHANTMENT_REIMBURSEMENT_RATE = 0.5;
166	
167	const findPolicyItem = (items: Item[], itemType: string): Item | undefined =>
168	  items.find((item) => item.type === itemType);
169	
170	const reimbursementBeforeDeductible = (damage: Damage, item: Item | undefined): number => {
171	  if (item && (item.enchantment as number) >= HIGH_ENCHANTMENT_CLAIM_THRESHOLD) {
172	    return damage.amount * HIGH_ENCHANTMENT_REIMBURSEMENT_RATE;
173	  }
174	  return damage.amount;
175	};
176	
177	const damageKey = (damage: Damage): string =>
178	  damage.itemType === "component"
179	    ? `component:${damage.componentType as string}`
180	    : damage.itemType;
181	
182	const itemKey = (item: Item): string =>
183	  item.type === "component"
184	    ? `component:${item.componentType as string}`
185	    : (item.type as string);
186	
187	const countByKey = <T>(values: T[], keyFn: (value: T) => string): Map<string, number> => {
188	  const counts = new Map<string, number>();
189	  for (const value of values) {
190	    const key = keyFn(value);
191	    counts.set(key, (counts.get(key) ?? 0) + 1);
192	  }
193	  return counts;
194	};
195	
196	const validateDamageCounts = (items: Item[], damages: Damage[]): void => {
197	  const itemCounts = countByKey(items, itemKey);
198	  const damageCounts = countByKey(damages, damageKey);
199	  for (const [key, count] of damageCounts) {
200	    if (count > (itemCounts.get(key) ?? 0)) {
201	      throw new Error(`More damages of type ${key} than insured`);
202	    }
203	  }
204	};
205	
206	export function claim(policy: { items: Item[] }, event: ClaimEvent): ClaimResult {
207	  validateDamageCounts(policy.items, event.damages);
208	  const payout = event.damages.reduce(
209	    (sum, damage) => {
210	      const item = findPolicyItem(policy.items, damage.itemType);
211	      return sum + (reimbursementBeforeDeductible(damage, item) - DEDUCTIBLE_PER_DAMAGE);
212	    },
213	    0,
214	  );
215	  const cap = CAP_MULTIPLIER * policy.items.reduce(
216	    (sum, item) => sum + insuranceValueForItem(item),
217	    0,
218	  );
219	  return { payout, remainingCap: cap - payout };
220	}
